customCss:
/* ═══ Post Captain — custom CSS (round 2) ═══ */
@import url('https://fonts.googleapis.com/css2?family=Poppins:ital,wght@0,300;0,400;0,500;0,600;0,700;1,600;1,700&family=DM+Sans:wght@300;400;500&display=swap');

.block-content h1, .block-content h2, .block-content h3, .block-content h4 {
  font-family: 'Poppins', system-ui, sans-serif !important;
  letter-spacing: -0.01em;
}
.block-content p, .block-content li, .block-content span {
  font-family: 'DM Sans', system-ui, sans-serif;
}

/* ─── Announcement bar ─── */
#pc-announce {
  background: #B5CCE0;
  color: #0A3A5C;
  text-align: center;
  font-family: 'DM Sans', system-ui, sans-serif;
  font-size: 14px;
  letter-spacing: 0.02em;
  padding: 24px 48px 24px 16px;
  position: fixed; top: 0; left: 0; right: 0; z-index: 60;
}
#pc-announce a { color: #0A3A5C; text-decoration: underline; text-underline-offset: 2px; font-weight: 500; margin-left: 6px; }
#pc-announce .pc-reg-btn { display: inline-block; background: #fff; color: #0A3A5C; font-weight: 700; letter-spacing: 0.08em; padding: 6px 20px; margin-left: 18px; border-radius: 4px; text-transform: uppercase; font-size: 12px; text-decoration: none; }
#pc-announce .pc-close { position: absolute; right: 12px; top: 50%; transform: translateY(-50%); background: transparent; border: 0; color: #0A3A5C; cursor: pointer; font-size: 20px; line-height: 1; }
body.pc-has-announce nav.fixed { top: 71px !important; }
body.pc-has-announce { padding-top: 71px; }

/* ─── Slate Platinum badge (real PNG) ─── */
#pc-slate-badge {
  position: absolute; top: 290px; right: 40px;
  width: 145px; height: auto; z-index: 50;
  pointer-events: none;
  filter: drop-shadow(0 12px 28px rgba(0,0,0,0.45));
}

/* ─── "Set Everyone Up for Success" card block ─── */
.block-content [data-block-id="set-everyone-up-card"] section.py-16 { padding: 0 !important; }
.block-content [data-block-id="set-everyone-up-card"] .grid {
  grid-template-columns: 1fr !important;
  gap: 0 !important;
  max-width: 540px;
  margin: 0 auto;
}
.block-content [data-block-id="set-everyone-up-card"] .grid > a > div, .block-content [data-block-id="set-everyone-up-card"] .grid > div {
  background: #EAF3EC !important;
  border: 1px solid #CCE1D0 !important;
  border-radius: 12px !important;
  padding: 28px 32px !important;
  box-shadow: 0 6px 18px rgba(10, 58, 92, 0.06) !important;
  backdrop-filter: none !important;
}
.block-content [data-block-id="set-everyone-up-card"] .grid > a > div, .block-content [data-block-id="set-everyone-up-card"] .grid > div:hover {
  border-color: #CCE1D0 !important;
  box-shadow: 0 8px 24px rgba(10, 58, 92, 0.08) !important;
}
.block-content [data-block-id="set-everyone-up-card"] .grid > a > div, .block-content [data-block-id="set-everyone-up-card"] .grid > div h3 {
  font-family: 'Poppins', system-ui, sans-serif !important;
  color: #0A3A5C !important;
  font-size: 22px !important;
  font-weight: 600 !important;
  letter-spacing: -0.01em !important;
  margin: 0 0 14px !important;
  text-align: left !important;
  text-transform: none !important;
}
.block-content [data-block-id="set-everyone-up-card"] .grid > a > div, .block-content [data-block-id="set-everyone-up-card"] .grid > div p {
  font-family: 'DM Sans', system-ui, sans-serif !important;
  color: #1F4F6F !important;
  font-size: 14px !important;
  line-height: 1.8 !important;
  white-space: pre-line !important;
  text-align: left !important;
  margin: 0 !important;
}

/* ─── Hero ─── */
.block-content [data-block-type="hero"] {
  background-color: #0A3A5C !important;
  position: relative;
}
.block-content [data-block-type="hero"]::before {
  content: "";
  position: absolute; inset: 0;
  background: transparent;
  pointer-events: none; z-index: 1;
}
.block-content [data-block-type="hero"] > *:not(.hero-bg) { position: relative; z-index: 2; }
.block-content [data-block-type="hero"] h1,
.block-content [data-block-type="hero"] h2 {
  text-shadow: 0 2px 30px rgba(0,0,0,0.5);
  /* letter-spacing: via block elementStyles */
  font-weight: 500 !important;
}
.block-content [data-block-type="hero"] a[href="/contact"] { box-shadow: 0 10px 28px rgba(0,0,0,0.22); border-radius: 6px !important; }
.block-content [data-block-type="hero"] a[href="/true-north"] { border-radius: 6px !important; }

/* ─── Tighten section spacing ─── */
.block-content > div[data-block-type] { margin: 0 !important; }
.block-content [data-block-type="section"] > div { padding-top: 56px; padding-bottom: 56px; }
.block-content [data-block-type="columns"] > div { gap: 40px !important; }
/* seu-list — checkmark bullets for success card */
.block-content [data-block-id="set-everyone-up-card"] .seu-list {
  list-style: none !important;
  padding: 0 !important;
  margin: 0 !important;
  display: grid !important;
  gap: 10px !important;
}
.block-content [data-block-id="set-everyone-up-card"] .seu-list li {
  display: flex !important;
  align-items: flex-start !important;
  gap: 12px !important;
  font-family: 'DM Sans', system-ui, sans-serif !important;
  font-size: 14px !important;
  line-height: 1.5 !important;
  color: #1F4F6F !important;
  padding-left: 0 !important;
  position: relative !important;
}
.block-content [data-block-id="set-everyone-up-card"] .seu-list li::before {
  content: "" !important;
  display: inline-block !important;
  flex: 0 0 18px !important;
  width: 18px !important;
  height: 18px !important;
  margin-top: 2px !important;
  background: #4C9770 !important;
  border-radius: 50% !important;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='white'><path d='M9 16.2l-3.5-3.5 1.4-1.4L9 13.4l7.1-7.1 1.4 1.4z'/></svg>") !important;
  background-position: center !important;
  background-repeat: no-repeat !important;
  background-size: 14px 14px !important;
}
/* /seu-list */
/* seu-cta — style the Learn More link on the success card as a solid pill */
.block-content [data-block-id="set-everyone-up-card"] a > div.flex.items-center {
  display: inline-flex !important;
  align-items: center;
  gap: 6px;
  margin-top: 18px !important;
  padding: 10px 20px !important;
  background: #0A3A5C !important;
  color: #fff !important;
  border-radius: 6px !important;
  text-transform: uppercase;
  letter-spacing: 0.08em !important;
  font-family: 'Poppins', system-ui, sans-serif !important;
  font-weight: 600 !important;
  font-size: 12px !important;
}
.block-content [data-block-id="set-everyone-up-card"] a > div.flex.items-center svg {
  color: #fff !important;
}
/* /seu-cta */
/* nav-cta — add LET'S TALK SLATE button to top nav */

#pc-nav-cta:hover {
  transform: translateY(-1px);
  box-shadow: 0 6px 18px rgba(10, 58, 92, 0.35) !important;
}
/* Nudge announcement bar's REGISTER button left on smaller screens */
@media (max-width: 900px) {

}
/* /nav-cta */
/* charting-icons — wrap SVG icons in a green rounded badge like target */
.block-content [data-block-id="solutions-section"] .grid > a > div > svg:first-child,
.block-content [data-block-id="solutions-section"] .grid > div > svg:first-child {
  width: 36px !important;
  height: 36px !important;
  padding: 7px !important;
  background: #E8F3EC !important;
  color: #4C9770 !important;
  border-radius: 10px !important;
  box-sizing: content-box !important;
  margin-bottom: 16px !important;
}
/* /charting-icons */

.block-content [data-block-id="portals-section"] h1,
.block-content [data-block-id="portals-section"] h2,
.block-content [data-block-id="portals-section"] h3,
.block-content [data-block-id="portals-section"] p {
  color: #fff !important;
}

/* seu-title-fix — force Success card title to brand blue */
.block-content [data-block-id="set-everyone-up-card"] h3,
.block-content [data-block-id="set-everyone-up-card"] h3.font-heading {
  color: #0A3A5C !important;
  font-family: 'Poppins', system-ui, sans-serif !important;
  font-size: 22px !important;
  font-weight: 700 !important;
  margin: 0 0 16px !important;
  letter-spacing: -0.01em !important;
}
/* /seu-title-fix */



/* portals-bg — soft pale blue matching target */
.block-content [data-block-id="portals-section"] h1,
.block-content [data-block-id="portals-section"] h2,
.block-content [data-block-id="portals-section"] h3 {
  color: #0A3A5C !important;
}
.block-content [data-block-id="portals-section"] p {
  color: #1F4F6F !important;
}
/* /portals-bg */
/* hero-height — removed: padding now controlled by block.style.customCSS */
/* logo-opacity — now controlled via block.style.opacity on each image */
.block-content [data-block-id="clients-logos"] img {
  max-height: 48px !important;
  width: auto !important;
  margin: 0 auto !important;
  object-fit: contain;
}
/* /logo-opacity */
/* text-inherit — force text-block <p> children to inherit wrapper typography */
.block-content [data-block-type="text"] > div > div > p {
  color: inherit !important;
  font-size: inherit !important;
  font-weight: inherit !important;
  letter-spacing: inherit !important;
  font-family: inherit !important;
  text-transform: inherit !important;
}
/* /text-inherit */
/* hero-watermark — subtle radial glow behind hero text */
.block-content [data-block-type="hero"]::after {
  content: "";
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  width: 720px;
  height: 720px;
  background: radial-gradient(circle at center, rgba(27, 111, 168, 0.25) 0%, transparent 70%);
  pointer-events: none;
  z-index: 1;
}
/* /hero-watermark */

/* feature-title — uppercase titles for feature cards */
.block-content [data-block-id="service-cards-section"] h3 {
  text-transform: uppercase !important;
  letter-spacing: 0.08em !important;
  font-size: 18px !important;
}
/* /feature-title */
/* heading-inherit — let heading block wrappers pass letter-spacing/font styles to inner headings */
.block-content [data-block-type="heading"] > div > div > h1,
.block-content [data-block-type="heading"] > div > div > h2,
.block-content [data-block-type="heading"] > div > div > h3,
.block-content [data-block-type="heading"] > div > div > h4 {
  letter-spacing: inherit !important;
  text-transform: inherit !important;
  font-family: inherit !important;
  font-size: inherit !important;
  font-weight: inherit !important;
  line-height: inherit !important;
  color: inherit !important;
}
/* /heading-inherit */
/* hero-bg-color — now via block.style.backgroundGradient */
/* hero-waves — removed per target match (solid gradient only) */



/* metric-cards-layout — match postcaptain 'Turning Slate' design */
.block-content [data-block-id="cs-metrics"] {
  padding: 0 !important;
}
.block-content [data-block-id="cs-metrics"] > section {
  padding: 0 24px !important;
}
.block-content [data-block-id="cs-metrics"] > section > .grid {
  max-width: 960px;
  margin: 0 auto;
  gap: 24px !important;
}
/* Card styling — flat white, rounded, soft border, relative for absolute logo */
.block-content [data-block-id="cs-metrics"] > section > .grid > a > div,
.block-content [data-block-id="cs-metrics"] > section > .grid > div > div {
  background: #FFFFFF !important;
  border: 1px solid #E5E9EE !important;
  border-radius: 14px !important;
  padding: 32px 32px 28px !important;
  box-shadow: 0 1px 3px rgba(10,58,92,0.04) !important;
  position: relative !important;
  min-height: 200px !important;
}
/* Value — big brand blue */
.block-content [data-block-id="cs-metrics"] > section > .grid [style*="font-size"] {
  font-size: clamp(2.4rem, 3.5vw, 3rem) !important;
  color: #0A3A5C !important;
  font-weight: 700 !important;
  line-height: 1.05 !important;
  margin-bottom: 10px !important;
  letter-spacing: -0.02em !important;
  max-width: calc(100% - 110px);
}
/* Suffix — lighter inside value */
.block-content [data-block-id="cs-metrics"] .pc-metric-suffix {
  font-weight: 400 !important;
  font-size: 0.65em !important;
  color: #0A3A5C !important;
  letter-spacing: normal;
  margin-left: 4px;
  display: inline;
}
/* Small uppercase label */
.block-content [data-block-id="cs-metrics"] > section > .grid [class*="tracking-[0.15em]"] {
  color: #1B6FA8 !important;
  font-size: 11.5px !important;
  font-weight: 700 !important;
  letter-spacing: 0.14em !important;
  line-height: 1.35 !important;
  text-transform: uppercase !important;
  margin-bottom: 0 !important;
  max-width: calc(100% - 110px);
}
/* Institution row — absolute top-right, logo only */
.block-content [data-block-id="cs-metrics"] > section > .grid .mt-6.pt-4 {
  position: absolute !important;
  top: 28px !important;
  right: 28px !important;
  margin: 0 !important;
  padding: 0 !important;
  border-top: 0 !important;
  max-width: 100px;
  justify-content: flex-end;
}
.block-content [data-block-id="cs-metrics"] > section > .grid .mt-6.pt-4 img {
  max-height: 52px !important;
  width: auto !important;
  object-fit: contain;
}
.block-content [data-block-id="cs-metrics"] > section > .grid .mt-6.pt-4 span {
  display: none !important;
}
/* Case Study link — normal-case brand blue bold at bottom */
.block-content [data-block-id="cs-metrics"] > section > .grid a .inline-flex {
  text-transform: none !important;
  letter-spacing: 0.01em !important;
  font-weight: 600 !important;
  font-size: 14px !important;
  color: #0A3A5C !important;
}
.block-content [data-block-id="cs-metrics"] > section > .grid a .inline-flex svg {
  width: 14px !important;
  height: 14px !important;
}
/* /metric-cards-layout */

/* nav-transparent-v1 — make top nav transparent over the hero to match target.
   Target's nav sits visually inside the hero, so we drop the white bg and switch
   link text to white. The announcement bar stays above (fixed top:0) and the nav
   sits beneath it via body.pc-has-announce nav.fixed { top:42px }. */
nav.fixed {
  background-color: transparent !important;
  border-bottom: 0 !important;
  box-shadow: none !important;
}
nav.fixed a:not([href="/contact"]),
nav.fixed a[style*="color"]:not([href="/contact"]) {
  color: #ffffff !important;
}
/* nav Contact link hide — removed; SiteNavClient now renders the CTA */
/* nav img filter removed — logo already designed for dark bg */
/* /nav-transparent-v1 */

/* wave-contrast-v1 — lift wave PNG visibility. Further reduce the ::before gradient
   alpha so the PNG's flowing curves read clearly against the hero bg color. */
.block-content [data-block-type="hero"]::before {
  background: linear-gradient(180deg, rgba(10,58,92,0.05) 0%, rgba(8,53,90,0.20) 70%, rgba(7,44,71,0.35) 100%) !important;
}
/* /wave-contrast-v1 */
/* hero-center-y — removed, using block padding only */

/* hero-section-pad — remove section's py-20 so block padding is authoritative */
.block-content [data-block-type="hero"] section > div.container { padding-top: 0 !important; padding-bottom: 0 !important; }
/* /hero-section-pad */
/* hero-subblocks-style — trust bar pinned to hero bottom, heading + logos in a row */
.block-content [data-block-type="hero"] section.relative > div.hero-subblocks {
  position: absolute !important;
  left: 0; right: 0; bottom: 32px;
  z-index: 10;
  display: flex !important;
  align-items: center !important;
  gap: 24px !important;
  max-width: 1264px;
  margin: 0 auto;
  padding: 0 88px;
}
/* Heading wrapper — natural width on left */
.block-content [data-block-type="hero"] .hero-subblocks > div[data-block-id="clients-heading"] {
  flex: 0 0 auto;
}
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-heading"] h1,
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-heading"] h2,
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-heading"] h3,
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-heading"] h4 {
  margin: 0 !important;
  padding: 0 !important;
  white-space: nowrap !important;
}
/* Logos wrapper — take remaining space */
.block-content [data-block-type="hero"] .hero-subblocks > div[data-block-id="clients-logos"] {
  flex: 1 1 auto !important;
}
/* Kill the py-8/my-8 padding on the columns inner wrapper */
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-logos"] > div {
  padding: 0 !important;
  margin: 0 !important;
}
/* Logos row */
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-logos"] .flex.flex-row {
  display: flex !important;
  align-items: center !important;
  justify-content: space-between !important;
  gap: 20px !important;
  width: 100% !important;
}
/* Each logo column */
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-logos"] .flex.flex-row > div {
  flex: 1 1 0 !important;
  max-width: 125px !important;
  min-width: 0 !important;
}
/* Image figure — remove default margin */
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-logos"] figure {
  margin: 0 !important;
}
.block-content [data-block-type="hero"] .hero-subblocks [data-block-id="clients-logos"] img {
  max-height: 40px !important;
  width: auto !important;
  max-width: 115px !important;
  object-fit: contain !important;
  border-radius: 0 !important;
}
/* /hero-subblocks-style */

/* hero-section-fill — section fills full wrapper height so sub-blocks pin to hero bottom */
.block-content [data-block-type="hero"] > div {
  display: flex !important;
  flex-direction: column !important;
}
.block-content [data-block-type="hero"] > div > section {
  flex: 1 1 auto !important;
  min-height: 700px !important;
}
/* /hero-section-fill */


/* hero-wrapper-width — widen hero content wrapper so the title fits one line */
.block-content [data-block-type="hero"] .max-w-4xl { max-width: 960px !important; }
/* /hero-wrapper-width */


/* seu-list-global — widened scope for all detail panels */
.block-content .seu-list {
  list-style: none !important;
  padding: 0 !important;
  margin: 0 !important;
  display: grid !important;
  gap: 10px !important;
}
.block-content .seu-list li {
  display: flex !important;
  align-items: flex-start !important;
  gap: 12px !important;
  font-family: 'DM Sans', system-ui, sans-serif !important;
  font-size: 15px !important;
  line-height: 1.5 !important;
  color: #1F4F6F !important;
  padding-left: 0 !important;
