// Announcement bar
try {
  if (!document.getElementById('pc-announce')) {
    var bar = document.createElement('div');
    bar.id = 'pc-announce';
    bar.innerHTML = 'NEW TO SLATE? LEARN FROM FORMER CAPTAINS. UPCOMING DIVE DEEPER ON APRIL 21' +
      '<a href="#">&#x2197;&#xFE0F;</a>' +
      '<a class="pc-reg-btn" href="#">REGISTER</a>' +
      '<button class="pc-close" aria-label="Dismiss">&times;</button>';
    document.body.insertBefore(bar, document.body.firstChild);
    document.body.classList.add('pc-has-announce');
    var closeBtn = bar.querySelector('.pc-close');
    if (closeBtn) closeBtn.addEventListener('click', function(){ bar.remove(); document.body.classList.remove('pc-has-announce'); });
  }
} catch (e) { console.error('pc-announce', e); }

